export default class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private lastRefillTime: number;
  private readonly queue: Array<{ tokens: number; resolve: () => void }>;
  private timer: ReturnType<typeof setTimeout> | null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a positive finite number");
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0)
      throw new RangeError("refillRate must be a positive finite number");
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a positive finite number");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.queue = [];
    this.timer = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;
    this.tokens = Math.min(
      this.maxTokens,
      this.tokens + (elapsed / this.refillIntervalMs) * this.refillRate
    );
    this.lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens))
      throw new TypeError("tokens must be a finite number");
    if (tokens <= 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens))
      return Promise.reject(new TypeError("tokens must be a finite number"));
    if (tokens <= 0) return Promise.resolve();
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Cannot wait for ${tokens} tokens: exceeds capacity of ${this.maxTokens}`
        )
      );

    this.refill();

    if (this.queue.length === 0 && this.tokens >= tokens) {
      this.tokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.queue.push({ tokens, resolve });
      this.scheduleDrain();
    });
  }

  private scheduleDrain(): void {
    if (this.timer !== null || this.queue.length === 0) return;

    const next = this.queue[0];
    this.refill();
    const deficit = next.tokens - this.tokens;

    if (deficit <= 0) {
      this.timer = setTimeout(() => {
        this.timer = null;
        this.drainQueue();
      }, 0);
      return;
    }

    const waitMs = Math.ceil(
      (deficit / this.refillRate) * this.refillIntervalMs
    );
    this.timer = setTimeout(() => {
      this.timer = null;
      this.drainQueue();
    }, waitMs);
  }

  private drainQueue(): void {
    if (this.timer !== null) {
      clearTimeout(this.timer);
      this.timer = null;
    }

    this.refill();

    while (this.queue.length > 0) {
      const next = this.queue[0];
      if (this.tokens >= next.tokens) {
        this.tokens -= next.tokens;
        this.queue.shift();
        next.resolve();
      } else {
        break;
      }
    }

    this.scheduleDrain();
  }
}

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  for (const key of Object.keys(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      Object.keys(value as Record<string, unknown>).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, path, result);
    } else {
      result[path] = value;
    }
  }

  return result;
}

export default flattenObject;

export default class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new RangeError("maxTokens must be a positive finite number");
    if (!Number.isFinite(refillRate) || refillRate <= 0)
      throw new RangeError("refillRate must be a positive finite number");
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a positive finite number");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private assertValidCount(tokens: number): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("token count must be a positive finite number");
    }
  }

  tryConsume(tokens = 1): boolean {
    this.assertValidCount(tokens);
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    this.assertValidCount(tokens);
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); would block forever`
      );
    }

    while (true) {
      this.refill();

      if (this.tokens >= tokens) {
        this.tokens -= tokens;
        return;
      }

      const deficit = tokens - this.tokens;
      const msPerToken = this.refillIntervalMs / this.refillRate;
      const waitMs = Math.ceil(deficit * msPerToken);

      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(1, waitMs)));
    }
  }
}

