type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: unknown,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    return prefix ? { [prefix]: obj } : {};
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = obj;
    } else {
      obj.forEach((item, index) => {
        flattenObject(item, prefix ? `${prefix}.${index}` : `${index}`, result);
      });
    }
    return result;
  }

  const entries = Object.entries(obj as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object" && !Array.isArray(value) && Object.keys(value as object).length > 0) {
      flattenObject(value, newKey, result);
    } else if (Array.isArray(value) && value.length > 0) {
      flattenObject(value, newKey, result);
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

export default flattenObject;

export interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldDef {
  readonly key: keyof CronSchedule;
  readonly min: number;
  readonly max: number;
}

const FIELDS: readonly FieldDef[] = [
  { key: "minute", min: 0, max: 59 },
  { key: "hour", min: 0, max: 23 },
  { key: "dayOfMonth", min: 1, max: 31 },
  { key: "month", min: 1, max: 12 },
  { key: "dayOfWeek", min: 0, max: 6 },
];

function toInt(raw: string, field: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid numeric value "${raw}" in ${field}`);
  }
  return Number(raw);
}

function assertRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] in ${field}`);
  }
}

function expandSegment(segment: string, min: number, max: number, field: string): number[] {
  if (segment.split("/").length > 2) {
    throw new Error(`Invalid expression "${segment}" in ${field}`);
  }

  const [rangeExpr, stepRaw] = segment.split("/");
  const step = stepRaw !== undefined ? toInt(stepRaw, field) : 1;

  if (step < 1) {
    throw new Error(`Step must be positive in ${field}, got ${step}`);
  }

  let start: number;
  let end: number;

  if (rangeExpr === "*") {
    start = min;
    end = max;
  } else if (rangeExpr.includes("-")) {
    if (rangeExpr.split("-").length > 2) {
      throw new Error(`Invalid range "${rangeExpr}" in ${field}`);
    }
    const [lo, hi] = rangeExpr.split("-");
    start = toInt(lo, field);
    end = toInt(hi, field);
    if (start > end) {
      throw new Error(`Range start ${start} exceeds end ${end} in ${field}`);
    }
  } else {
    start = toInt(rangeExpr, field);
    end = start;
  }

  assertRange(start, min, max, field);
  assertRange(end, min, max, field);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseField(expr: string, { min, max, key }: FieldDef): number[] {
  if (!expr) {
    throw new Error(`Empty expression for ${key}`);
  }

  const segments = expr.split(",");
  const seen = new Set<number>();
  const values: number[] = [];

  for (const segment of segments) {
    if (!segment) {
      throw new Error(`Empty segment in comma-separated list for ${key}`);
    }
    for (const v of expandSegment(segment, min, max, key)) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronSchedule {
  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${tokens.length}: "${expression}"`
    );
  }

  const schedule = {} as CronSchedule;
  for (let i = 0; i < FIELDS.length; i++) {
    schedule[FIELDS[i].key] = parseField(tokens[i], FIELDS[i]);
  }
  return schedule;
}

