class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;
  private readonly queue: Array<{ tokens: number; resolve: () => void }>;
  private pendingTimer: ReturnType<typeof setTimeout> | null;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new Error("maxTokens must be a positive finite number");
    if (!Number.isFinite(refillRate) || refillRate <= 0)
      throw new Error("refillRate must be a positive finite number");
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new Error("refillIntervalMs must be a positive finite number");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.queue = [];
    this.pendingTimer = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens)) return false;
    if (tokens <= 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.processQueue();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new Error("tokens must be a non-negative finite number");
    if (tokens === 0) return;
    if (tokens > this.maxTokens)
      throw new Error(
        `Requested ${tokens} tokens exceeds maximum capacity of ${this.maxTokens}`
      );

    this.refill();

    // Fast path: enough tokens and no queued waiters (FIFO fairness)
    if (this.tokens >= tokens && this.queue.length === 0) {
      this.tokens -= tokens;
      return;
    }

    return new Promise<void>((resolve) => {
      this.queue.push({ tokens, resolve });
      this.scheduleProcessQueue();
    });
  }

  private processQueue(): void {
    if (this.pendingTimer !== null) {
      clearTimeout(this.pendingTimer);
      this.pendingTimer = null;
    }

    this.refill();

    // Drain the queue head-first to preserve FIFO ordering and
    // prevent starvation of large requests by small ones.
    while (this.queue.length > 0) {
      const next = this.queue[0]!;
      if (this.tokens >= next.tokens) {
        this.tokens -= next.tokens;
        this.queue.shift();
        next.resolve();
      } else {
        break;
      }
    }

    this.scheduleProcessQueue();
  }

  private scheduleProcessQueue(): void {
    if (this.pendingTimer !== null || this.queue.length === 0) return;

    this.refill();

    const next = this.queue[0]!;
    const deficit = next.tokens - this.tokens;

    let waitMs: number;
    if (deficit <= 0) {
      // Tokens became available between processQueue's loop exit and here
      // (e.g. a resolve callback triggered reset). Drain on next microtask.
      waitMs = 0;
    } else {
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const targetTime =
        this.lastRefillTime + intervalsNeeded * this.refillIntervalMs;
      waitMs = Math.max(1, targetTime - Date.now());
    }

    this.pendingTimer = setTimeout(() => {
      this.pendingTimer = null;
      this.processQueue();
    }, waitMs);
  }
}

export default RateLimiter;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELDS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (token: string, { name, min, max }: FieldConfig): number[] => {
  const allValues = range(min, max);

  if (token === "*") return allValues;

  // Comma-separated list — split and recurse, then dedupe and sort
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), { name, min, max }));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step: */n or range/n
  if (token.includes("/")) {
    const [rangeStr, stepStr] = token.split("/");
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in field "${name}"`);
    }
    const base =
      rangeStr === "*"
        ? allValues
        : parseField(rangeStr, { name, min, max });
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  // Range: a-b
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = Number(startStr);
    const end = Number(endStr);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new Error(`Invalid range "${token}" in field "${name}"`);
    }
    if (start < min || end > max) {
      throw new Error(
        `Range "${token}" out of bounds [${min}-${max}] for field "${name}"`
      );
    }
    if (start > end) {
      // Wrap-around (e.g., dayOfWeek 5-2 means 5,6,0,1,2)
      return [...range(start, max), ...range(min, end)];
    }
    return range(start, end);
  }

  // Single value
  const value = Number(token);
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new Error(
      `Value "${token}" out of bounds [${min}-${max}] for field "${name}"`
    );
  }
  return [value];
};

const parseCron = (expression: string): CronSchedule => {
  const tokens = expression.trim().split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${tokens.length} in "${expression}"`
    );
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = tokens.map(
    (token, i) => parseField(token, FIELDS[i])
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(value) ? value as unknown as Primitive : value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_DEFS: readonly [keyof CronSchedule, number, number][] = [
  ["minute", 0, 59],
  ["hour", 0, 23],
  ["dayOfMonth", 1, 31],
  ["month", 1, 12],
  ["dayOfWeek", 0, 6],
];

const parseField = (expr: string, min: number, max: number, name: string): number[] => {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    const [rangeStr, stepStr] = part.split("/");
    const step = stepStr !== undefined ? parseInt(stepStr, 10) : 1;

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step in "${name}": ${part}`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end = max;
    } else if (rangeStr.includes("-")) {
      const bounds = rangeStr.split("-").map(Number);
      if (bounds.length !== 2 || bounds.some(isNaN)) {
        throw new Error(`Invalid range in "${name}": ${part}`);
      }
      [start, end] = bounds;
    } else {
      const num = parseInt(rangeStr, 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value in "${name}": ${part}`);
      }
      start = num;
      end = num;
    }

    if (start < min || end > max) {
      throw new Error(`Out of range in "${name}": ${part} (valid: ${min}-${max})`);
    }
    if (start > end) {
      throw new Error(`Invalid range in "${name}": ${start} > ${end}`);
    }

    for (let i = start; i <= end; i += step) {
      values.add(i);
    }
  }

  return [...values].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronSchedule => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  return Object.fromEntries(
    FIELD_DEFS.map(([name, min, max], i) => [name, parseField(fields[i], min, max, name)])
  ) as CronSchedule;
};

export default parseCron;

