    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new Error("Tokens must be positive");
    if (tokens > this.maxTokens) throw new Error("Requested tokens exceed max capacity");
    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      await new Promise((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

