  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronSchedule;
  min: number;
  max: number;
}

const FIELDS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (token: string, { name, min, max }: FieldConfig): number[] => {
  const values = token.split(",").flatMap((part) => {
    const stepMatch = part.match(/^(.+)\/(\d+)$/);
    const step = stepMatch ? parseInt(stepMatch[2], 10) : null;
    const base = stepMatch ? stepMatch[1] : part;

    if (step !== null && (step < 1 || step > max)) {
      throw new Error(`Invalid step value "${step}" for field "${name}"`);
    }

    let pool: number[];

    if (base === "*") {
      pool = range(min, max);
    } else if (base.includes("-")) {
      const [startStr, endStr] = base.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end) || start > end || start < min || end > max) {
        throw new Error(`Invalid range "${base}" for field "${name}" (valid: ${min}-${max})`);
      }
      pool = range(start, end);
    } else {
      const val = parseInt(base, 10);
      if (isNaN(val) || val < min || val > max) {
        throw new Error(`Invalid value "${base}" for field "${name}" (valid: ${min}-${max})`);
      }
      pool = [val];
    }

    return step !== null ? pool.filter((v) => (v - pool[0]) % step === 0) : pool;
  });

  const unique = [...new Set(values)].sort((a, b) => a - b);

  if (unique.length === 0) {
    throw new Error(`Field "${name}" resolved to no valid values`);
  }

  return unique;
};

function parseCron(expression: string): CronSchedule {
  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${tokens.length}: "${expression}"`,
    );
  }

  return Object.fromEntries(
    FIELDS.map((field, i) => [field.name, parseField(tokens[i], field)]),
  ) as CronSchedule;
}

