interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldDef {
  name: keyof CronSchedule;
  min: number;
  max: number;
}

const FIELDS: FieldDef[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function rangeArray(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(token: string, { name, min, max }: FieldDef): number[] {
  const values = new Set<number>();

  for (const part of token.split(",")) {
    const trimmed = part.trim();
    if (trimmed === "") throw new Error(`Empty sub-expression in field "${name}"`);

    const [baseExpr, stepStr, ...rest] = trimmed.split("/");
    if (rest.length > 0) throw new Error(`Invalid step syntax "${trimmed}" in field "${name}"`);

    let step: number | undefined;
    if (stepStr !== undefined) {
      step = Number(stepStr);
      if (!Number.isInteger(step) || step < 1) {
        throw new Error(`Invalid step value "${stepStr}" in field "${name}"`);
      }
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (baseExpr === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (baseExpr.includes("-")) {
      const [lo, hi, ...extra] = baseExpr.split("-");
      if (extra.length > 0) throw new Error(`Invalid range "${baseExpr}" in field "${name}"`);

      rangeStart = Number(lo);
      rangeEnd = Number(hi);

      if (!Number.isInteger(rangeStart) || !Number.isInteger(rangeEnd)) {
        throw new Error(`Non-integer in range "${baseExpr}" in field "${name}"`);
      }
      if (rangeStart > rangeEnd) {
        throw new Error(`Range start ${rangeStart} > end ${rangeEnd} in field "${name}"`);
      }
      if (rangeStart < min || rangeEnd > max) {
        throw new Error(
          `Range "${baseExpr}" out of bounds [${min}-${max}] in field "${name}"`
        );
      }
    } else {
      const num = Number(baseExpr);
      if (!Number.isInteger(num)) {
        throw new Error(`Invalid value "${baseExpr}" in field "${name}"`);
      }
      if (num < min || num > max) {
        throw new Error(
          `Value ${num} out of bounds [${min}-${max}] in field "${name}"`
        );
      }
      if (step !== undefined) {
        rangeStart = num;
        rangeEnd = max;
      } else {
        values.add(num);
        continue;
      }
    }

    const effectiveStep = step ?? 1;
    for (let i = rangeStart; i <= rangeEnd; i += effectiveStep) {
      values.add(i);
    }
  }

  if (values.size === 0) {
    throw new Error(`Field "${name}" resolved to no values`);
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const tokens = expression.trim().split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as CronSchedule;
  for (let i = 0; i < FIELDS.length; i++) {
    result[FIELDS[i].name] = parseField(tokens[i], FIELDS[i]);
  }

  return result;
}

export default parseCron;

