  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new Error("Token count must be positive");
    if (tokens > this.maxTokens) throw new Error("Requested tokens exceed max capacity");
    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      await new Promise((resolve) => setTimeout(resolve, Math.max(waitMs, 1)));
    }
  }
}

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronSchedule;
  min: number;
  max: number;
}

const FIELDS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, { name, min, max }: FieldConfig): number[] => {
  const parts = field.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const [rangeExpr, stepStr] = part.split("/");
    const step = stepStr !== undefined ? parseIntStrict(stepStr, `step in field "${name}"`) : undefined;

    if (step !== undefined && (step < 1 || !Number.isInteger(step))) {
      throw new Error(`Invalid step value "${stepStr}" in field "${name}"`);
    }

    let candidates: number[];

    if (rangeExpr === "*") {
      candidates = range(min, max);
    } else if (rangeExpr.includes("-")) {
      const [startStr, endStr] = rangeExpr.split("-");
      const start = parseIntStrict(startStr, `range start in field "${name}"`);
      const end = parseIntStrict(endStr, `range end in field "${name}"`);
      validateRange(start, min, max, name);
      validateRange(end, min, max, name);
      if (start > end) {
        throw new Error(`Invalid range "${rangeExpr}" in field "${name}": start exceeds end`);
      }
      candidates = range(start, end);
    } else {
      const value = parseIntStrict(rangeExpr, `value in field "${name}"`);
      validateRange(value, min, max, name);
      candidates = step !== undefined ? range(value, max) : [value];
    }

    if (step !== undefined) {
      const base = candidates[0];
      for (const v of candidates) {
        if ((v - base) % step === 0) values.add(v);
      }
    } else {
      for (const v of candidates) values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
};

const parseIntStrict = (str: string, context: string): number => {
  const n = Number(str);
  if (!Number.isInteger(n) || str.trim() === "") {
    throw new Error(`Invalid integer "${str}" for ${context}`);
  }
  return n;
};

const validateRange = (value: number, min: number, max: number, name: string): void => {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] for field "${name}"`);
  }
};

const parseCron = (expression: string): CronSchedule => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  return Object.fromEntries(
    FIELDS.map((config, i) => [config.name, parseField(parts[i], config)])
  ) as CronSchedule;
};

export default parseCron;

type FlatResult = Record<string, unknown>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: FlatResult = {},
): FlatResult {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      Object.keys(value as Record<string, unknown>).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, path, result);
    } else {
      result[path] = value;
    }
  }

  return result;
}

