interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private lastRefillTime: number;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (refillRate <= 0) throw new Error("refillRate must be positive");
    if (refillIntervalMs <= 0) throw new Error("refillIntervalMs must be positive");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) return;
    if (tokens > this.maxTokens) {
      throw new Error(
        `Requested ${tokens} tokens exceeds max capacity of ${this.maxTokens}`
      );
    }

    while (true) {
      this.refill();

      if (this.tokens >= tokens) {
        this.tokens -= tokens;
        return;
      }

      const deficit = tokens - this.tokens;
      const waitMs = (deficit / this.refillRate) * this.refillIntervalMs;

      await new Promise((resolve) =>
        setTimeout(resolve, Math.max(1, Math.ceil(waitMs)))
      );
    }
  }
}

