  for (const part of field.split(",")) {
    let range: string;
    let step = 1;

    if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      range = rangePart === "*" ? `${min}-${max}` : rangePart;
      step = Number(stepPart);
      if (!Number.isInteger(step) || step < 1) throw new Error(`Invalid step: ${stepPart}`);
    } else if (part === "*") {
