];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseAtom = (atom: string, min: number, max: number): number[] => {
  const [baseExpr, stepStr] = atom.split("/");
  const step = stepStr !== undefined ? parseInt(stepStr, 10) : undefined;

  if (step !== undefined && (isNaN(step) || step < 1)) {
    throw new Error(`Invalid step value: ${stepStr}`);
  }

  let values: number[];

  if (baseExpr === "*") {
    values = range(min, max);
  } else if (baseExpr.includes("-")) {
    const [startStr, endStr] = baseExpr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range: ${baseExpr}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range ${baseExpr} out of bounds [${min}-${max}]`);
    }
    values = range(start, end);
  } else {
    const num = parseInt(baseExpr, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid value: ${baseExpr}`);
    }
    if (num < min || num > max) {
      throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
    }
    values = step !== undefined ? range(num, max) : [num];
  }

  return step !== undefined
    ? values.filter((_, i) => i % step === 0)
    : values;
};

const parseField = (field: string, min: number, max: number): number[] => {
  const parts = field.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    for (const value of parseAtom(part.trim(), min, max)) {
      seen.add(value);
    }
  }

  return [...seen].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronSchedule => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  return FIELD_CONFIGS.reduce((schedule, config, i) => {
    schedule[config.name] = parseField(fields[i], config.min, config.max);
    return schedule;
  }, {} as CronSchedule);
};

