function expandRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(raw: string, def: FieldDef): number[] {
  const { name, min, max } = def;
  const values = new Set<number>();

  const parts = raw.split(",");
  if (parts.length === 0 || parts.some((p) => p === "")) {
    throw new Error(`Empty segment in field "${name}": "${raw}"`);
  }

  for (const part of parts) {
    let base: string;
    let step: number | null = null;

    const slashIdx = part.indexOf("/");
    if (slashIdx !== -1) {
      base = part.slice(0, slashIdx);
      const stepStr = part.slice(slashIdx + 1);
      if (!/^\d+$/.test(stepStr)) {
        throw new Error(`Invalid step value in field "${name}": "${part}"`);
      }
      step = Number(stepStr);
      if (step === 0) {
        throw new Error(`Step value must be > 0 in field "${name}": "${part}"`);
      }
    } else {
      base = part;
    }

    if (base === "*") {
      for (const v of expandRange(min, max, step ?? 1)) values.add(v);
    } else if (/^\d+-\d+$/.test(base)) {
      const [startStr, endStr] = base.split("-");
      const start = Number(startStr);
      const end = Number(endStr);
      if (start < min || start > max) {
        throw new Error(
          `Range start ${start} out of bounds [${min}-${max}] in field "${name}"`,
        );
      }
      if (end < min || end > max) {
        throw new Error(
          `Range end ${end} out of bounds [${min}-${max}] in field "${name}"`,
        );
      }
      if (start > end) {
        throw new Error(
          `Range start ${start} > end ${end} in field "${name}"`,
        );
      }
      for (const v of expandRange(start, end, step ?? 1)) values.add(v);
    } else if (/^\d+$/.test(base)) {
      if (step !== null) {
        // "N/S" means starting at N, step by S through max
        const start = Number(base);
        if (start < min || start > max) {
          throw new Error(
            `Value ${start} out of bounds [${min}-${max}] in field "${name}"`,
          );
        }
        for (const v of expandRange(start, max, step)) values.add(v);
      } else {
        const num = Number(base);
        if (num < min || num > max) {
          throw new Error(
            `Value ${num} out of bounds [${min}-${max}] in field "${name}"`,
          );
        }
        values.add(num);
      }
    } else {
      throw new Error(`Unrecognized token "${base}" in field "${name}"`);
    }
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronSchedule {
  const trimmed = expression.trim();
  const segments = trimmed.split(/\s+/);

  if (segments.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${segments.length}: "${expression}"`,
    );
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = segments.map(
    (seg, i) => parseField(seg, FIELDS[i]),
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

