  }

  const tokens = expression.trim().split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${tokens.length}: "${expression}"`
    );
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = FIELDS.map((field, i) =>
    parseField(tokens[i], field)
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIG: { name: keyof CronFields; min: number; max: number }[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function parseField(field: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of field.split(",")) {
    const stepMatch = part.match(/^(.+)\/(\d+)$/);
    const step = stepMatch ? parseInt(stepMatch[2]) : 1;
    const base = stepMatch ? stepMatch[1] : part;

    if (step < 1) throw new Error(`Invalid step: ${step}`);

    let start: number, end: number;

    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      const [a, b] = base.split("-").map(Number);
      if (isNaN(a) || isNaN(b)) throw new Error(`Invalid range: ${base}`);
      start = a;
      end = b;
    } else {
      const val = parseInt(base);
      if (isNaN(val)) throw new Error(`Invalid value: ${base}`);
      if (stepMatch) {
        start = val;
        end = max;
      } else {
        start = val;
        end = val;
      }
    }

    if (start < min || start > max || end < min || end > max) {
      throw new Error(`Value out of range [${min}-${max}]: ${part}`);
    }
    if (start > end) throw new Error(`Invalid range: ${start}-${end}`);

    for (let i = start; i <= end; i += step) results.add(i);
  }

  return [...results].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const result = {} as CronFields;
  for (let i = 0; i < 5; i++) {
    const { name, min, max } = FIELD_CONFIG[i];
    result[name] = parseField(fields[i], min, max);
  }
  return result;
}

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
): FlattenedObject {
  const result: FlattenedObject = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      Object.assign(
        result,
        flattenObject(value as Record<string, unknown>, newKey),
      );
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

