interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldDef {
  readonly name: keyof CronSchedule;
  readonly min: number;
  readonly max: number;
}

const FIELDS: readonly FieldDef[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function toInt(raw: string, ctx: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new RangeError(`Non-integer value "${raw}" in ${ctx}`);
  }
  return Number(raw);
}

function assertBounds(value: number, def: FieldDef, ctx: string): void {
  if (value < def.min || value > def.max) {
    throw new RangeError(
      `${ctx}: ${value} outside valid range [${def.min}–${def.max}] for ${def.name}`
    );
  }
}

function expandAtom(token: string, def: FieldDef): number[] {
  // Step: "*/n" or "a-b/n" or "a/n"
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const baseStr = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);
    const step = toInt(stepStr, `${def.name} step`);
    if (step === 0) {
      throw new RangeError(`Step value cannot be 0 in ${def.name}`);
    }

    let start: number;
    let end: number;

    if (baseStr === "*") {
      start = def.min;
      end = def.max;
    } else if (baseStr.includes("-")) {
      const [lo, hi] = baseStr.split("-");
      start = toInt(lo, def.name);
      end = toInt(hi, def.name);
      assertBounds(start, def, "range start");
      assertBounds(end, def, "range end");
      if (start > end) {
        throw new RangeError(`Invalid range ${start}-${end} in ${def.name}`);
      }
    } else {
      start = toInt(baseStr, def.name);
      assertBounds(start, def, "step base");
      end = def.max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: "a-b"
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) {
      throw new RangeError(`Malformed range "${token}" in ${def.name}`);
    }
    const start = toInt(parts[0], def.name);
    const end = toInt(parts[1], def.name);
    assertBounds(start, def, "range start");
    assertBounds(end, def, "range end");
    if (start > end) {
      throw new RangeError(`Invalid range ${start}-${end} in ${def.name}`);
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (token === "*") {
    const values: number[] = [];
    for (let i = def.min; i <= def.max; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const value = toInt(token, def.name);
  assertBounds(value, def, "value");
  return [value];
}

function parseField(raw: string, def: FieldDef): number[] {
  if (raw === "") {
    throw new RangeError(`Empty field for ${def.name}`);
  }

  // Comma-separated list — each element is an atom (number, range, wildcard, step)
  const atoms = raw.split(",");
  const seen = new Set<number>();
  for (const atom of atoms) {
    const trimmed = atom.trim();
    if (trimmed === "") {
      throw new RangeError(`Trailing/double comma in ${def.name} field`);
    }
    for (const v of expandAtom(trimmed, def)) {
      seen.add(v);
    }
  }
  return [...seen].sort((a, b) => a - b);
}

function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new RangeError("Cron expression cannot be empty");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new RangeError(
      `Expected 5 fields but got ${tokens.length}: "${trimmed}"`
    );
  }

  const parsed = tokens.map((token, i) => parseField(token, FIELDS[i]));

  return {
    minute: parsed[0],
    hour: parsed[1],
    dayOfMonth: parsed[2],
    month: parsed[3],
    dayOfWeek: parsed[4],
  };
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly _maxTokens: number;
  private readonly _refillRate: number;
  private readonly _refillIntervalMs: number;
  private _tokens: number;
  private _lastRefillTime: number;
  private readonly _queue: Array<{ tokens: number; resolve: () => void }> = [];
  private _draining = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a positive finite number");
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0)
      throw new RangeError("refillRate must be a positive finite number");
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a positive finite number");

    this._maxTokens = options.maxTokens;
    this._refillRate = options.refillRate;
    this._refillIntervalMs = options.refillIntervalMs;
    this._tokens = options.maxTokens;
    this._lastRefillTime = Date.now();
  }

  private _refill(): void {
    const now = Date.now();
    const elapsed = now - this._lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed * this._refillRate) / this._refillIntervalMs;
    this._tokens = Math.min(this._maxTokens, this._tokens + tokensToAdd);
    this._lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) return true;
    if (tokens > this._maxTokens) return false;

    this._refill();
    if (this._tokens >= tokens) {
      this._tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this._refill();
    return this._tokens;
  }

  reset(): void {
    this._tokens = this._maxTokens;
    this._lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) return;
    if (tokens > this._maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this._maxTokens}`
      );
    }

    return new Promise<void>((resolve) => {
      this._queue.push({ tokens, resolve });
      this._drainQueue();
    });
  }

  private async _drainQueue(): Promise<void> {
    if (this._draining) return;
    this._draining = true;

    try {
      while (this._queue.length > 0) {
        const head = this._queue[0]!;
        this._refill();

        if (this._tokens >= head.tokens) {
          this._tokens -= head.tokens;
          this._queue.shift();
          head.resolve();
        } else {
          const deficit = head.tokens - this._tokens;
          const waitMs = Math.ceil(
            (deficit * this._refillIntervalMs) / this._refillRate
          );
          await new Promise<void>((r) => setTimeout(r, Math.max(1, waitMs)));
        }
      }
    } finally {
      this._draining = false;
    }
  }
}

export default RateLimiter;

