interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELDS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (token: string, { name, min, max }: FieldConfig): number[] => {
  const allValues = range(min, max);

  if (token === "*") return allValues;

  // Comma-separated list — split and recurse, then deduplicate and sort
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), { name, min, max }));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */n or range/n
  if (token.includes("/")) {
    const [rangeToken, stepStr] = token.split("/");
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in field "${name}"`);
    }
    const base = rangeToken === "*" ? allValues : parseField(rangeToken, { name, min, max });
    return base.filter((_, i) => i % step === 0);
  }

  // Range: a-b
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = Number(startStr);
    const end = Number(endStr);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new Error(`Invalid range "${token}" in field "${name}"`);
    }
    if (start < min || end > max) {
      throw new Error(
        `Range "${token}" out of bounds [${min}-${max}] in field "${name}"`
      );
    }
    if (start > end) {
      // Wrap-around (e.g., dayOfWeek 5-2 means 5,6,0,1,2)
      return [...range(start, max), ...range(min, end)];
    }
    return range(start, end);
  }

  // Single number
  const value = Number(token);
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new Error(
      `Invalid value "${token}" in field "${name}" (must be ${min}-${max})`
    );
  }
  return [value];
};

const parseCron = (expression: string): CronSchedule => {
  const tokens = expression.trim().split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${tokens.length}: "${expression}"`
    );
  }

  const results = tokens.map((token, i) => parseField(token, FIELDS[i]));

  return {
    minute: results[0],
    hour: results[1],
    dayOfMonth: results[2],
    month: results[3],
    dayOfWeek: results[4],
  };
};

export default parseCron;

