interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldDef {
  name: string;
  min: number;
  max: number;
}

const FIELDS: FieldDef[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function expandRange(min: number, max: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function parseNumber(raw: string): number {
  if (!/^\d+$/.test(raw)) throw new Error(`Invalid numeric value: "${raw}"`);
  return Number(raw);
}

function parseField(field: string, def: FieldDef): number[] {
  const { name, min, max } = def;

  const validate = (v: number): number => {
    if (v < min || v > max)
      throw new Error(
        `${name} value ${v} out of range [${min}-${max}]`
      );
    return v;
  };

  // Comma-separated list — split first, then parse each part
  const parts = field.split(",");
  if (parts.length > 1) {
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), def)) {
        seen.add(v);
      }
    }
    return [...seen].sort((a, b) => a - b);
  }

  const token = parts[0].trim();
  if (token === "") throw new Error(`Empty ${name} field`);

  // Wildcard with optional step: "*" or "*/N"
  if (token.startsWith("*")) {
    if (token === "*") return expandRange(min, max, 1);
    if (token[1] !== "/")
      throw new Error(`Invalid wildcard expression: "${token}"`);
    const step = parseNumber(token.slice(2));
    return expandRange(min, max, step);
  }

  // Range with optional step: "A-B" or "A-B/N"
  if (token.includes("-")) {
    const [rangePart, stepPart] = token.split("/");
    const [startStr, endStr] = rangePart.split("-");
    if (startStr === undefined || endStr === undefined)
      throw new Error(`Invalid range: "${token}"`);

    const start = validate(parseNumber(startStr));
    const end = validate(parseNumber(endStr));
    if (start > end)
      throw new Error(
        `Invalid range in ${name}: ${start} > ${end}`
      );

    const step = stepPart !== undefined ? parseNumber(stepPart) : 1;
    return expandRange(start, end, step);
  }

  // Plain number with optional step: "N" or "N/S" (uncommon but valid in some cron impls — treat N/S as start at N, step S through max)
  if (token.includes("/")) {
    const [baseStr, stepStr] = token.split("/");
    const base = validate(parseNumber(baseStr));
    const step = parseNumber(stepStr);
    return expandRange(base, max, step);
  }

  // Single number
  return [validate(parseNumber(token))];
}

function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string")
    throw new Error("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(
      `Cron expression must have 5 fields, got ${parts.length}: "${expression}"`
    );

  const [minute, hour, dayOfMonth, month, dayOfWeek] = FIELDS.map(
    (def, i) => parseField(parts[i], def)
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIG: { name: keyof CronFields; min: number; max: number }[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function parseField(field: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of field.split(",")) {
    const [rangeStr, stepStr] = part.split("/");
    const step = stepStr ? parseInt(stepStr, 10) : 1;

    if (step < 1 || !Number.isInteger(step)) throw new Error(`Invalid step: ${stepStr}`);

    let start: number, end: number;

    if (rangeStr === "*") {
      start = min;
      end = max;
    } else if (rangeStr.includes("-")) {
      const [a, b] = rangeStr.split("-").map(Number);
      if (isNaN(a) || isNaN(b) || a < min || b > max || a > b)
        throw new Error(`Invalid range: ${rangeStr}`);
      start = a;
      end = b;
    } else {
      const val = parseInt(rangeStr, 10);
      if (isNaN(val) || val < min || val > max) throw new Error(`Invalid value: ${rangeStr}`);
      start = val;
      end = stepStr ? max : val;
    }

    for (let i = start; i <= end; i += step) results.add(i);
  }

  return [...results].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const result = {} as CronFields;
  for (let i = 0; i < 5; i++) {
    const { name, min, max } = FIELD_CONFIG[i];
    result[name] = parseField(fields[i], min, max);
  }
  return result;
}

