interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number, step = 1): number[] =>
  Array.from({ length: Math.floor((end - start) / step) + 1 }, (_, i) => start + i * step);

const parseAtom = (atom: string, { min, max, name }: FieldConfig): number[] => {
  const [base, stepStr] = atom.split("/");
  const step = stepStr !== undefined ? parseInt(stepStr, 10) : undefined;

  if (step !== undefined && (isNaN(step) || step < 1)) {
    throw new Error(`Invalid step value in "${atom}" for ${name}`);
  }

  let values: number[];

  if (base === "*") {
    values = range(min, max);
  } else if (base.includes("-")) {
    const [startStr, endStr] = base.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range "${base}" for ${name}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range "${base}" out of bounds [${min}-${max}] for ${name}`);
    }
    values = range(start, end);
  } else {
    const value = parseInt(base, 10);
    if (isNaN(value) || value < min || value > max) {
      throw new Error(`Value "${base}" out of bounds [${min}-${max}] for ${name}`);
    }
    values = step !== undefined ? range(value, max) : [value];
  }

  return step !== undefined ? values.filter((_, i) => i % step === 0) : values;
};

const parseField = (field: string, config: FieldConfig): number[] => {
  const values = field
    .split(",")
    .flatMap((atom) => parseAtom(atom.trim(), config));

  const unique = [...new Set(values)].sort((a, b) => a - b);

  if (unique.length === 0) {
    throw new Error(`Empty result for ${config.name} field "${field}"`);
  }

  return unique;
};

const parseCron = (expression: string): CronSchedule => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = fields.map((field, i) =>
    parseField(field, FIELD_CONFIGS[i])
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
};

