    const step = stepStr !== undefined ? toInt(stepStr, field.name, "step") : 1;

    if (step < 1) {
      throw new Error(
        `Step must be >= 1, got ${step} in field "${field.name}"`
      );
    }

    if (stepStr !== undefined && step > field.max - field.min + 1) {
      throw new Error(
        `Step ${step} exceeds range of field "${field.name}" (${field.min}-${field.max})`
      );
    }

    let start: number;
    let end: number;

    if (rangeExpr === "*") {
      start = field.min;
      end = field.max;
    } else if (rangeExpr.includes("-")) {
      const [lo, hi, ...extra] = rangeExpr.split("-");
      if (extra.length > 0) {
        throw new Error(
          `Invalid range "${rangeExpr}" in field "${field.name}"`
        );
      }
      start = toInt(lo, field.name, "range start");
      end = toInt(hi, field.name, "range end");
      if (start > end) {
        throw new Error(
          `Range start (${start}) > end (${end}) in field "${field.name}"`
        );
      }
    } else {
      const val = toInt(rangeExpr, field.name, "value");
      start = val;
      end = stepStr !== undefined ? field.max : val;
    }

    validateBounds(start, field);
    validateBounds(end, field);

    for (let i = start; i <= end; i += step) {
      valueSet.add(i);
    }
  }

  return [...valueSet].sort((a, b) => a - b);
}

function toInt(raw: string, fieldName: string, context: string): number {
  if (raw === "" || raw === undefined) {
    throw new Error(`Missing ${context} in field "${fieldName}"`);
  }
  if (!/^[0-9]+$/.test(raw)) {
    throw new Error(
      `Invalid ${context} "${raw}" in field "${fieldName}": expected an integer`
    );
  }
  return Number(raw);
}

function validateBounds(value: number, field: FieldDef): void {
  if (value < field.min || value > field.max) {
    throw new Error(
      `Value ${value} out of range for field "${field.name}" (${field.min}-${field.max})`
    );
  }
}

function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${tokens.length}: "${trimmed}"`
    );
  }

  const results = tokens.map((token, i) => parseField(token, FIELDS[i]));

  return {
    minute: results[0],
    hour: results[1],
    dayOfMonth: results[2],
    month: results[3],
    dayOfWeek: results[4],
  };
}

export default parseCron;

interface RateLimiterOptions {
  readonly maxTokens: number;
  readonly refillRate: number;
  readonly refillIntervalMs: number;
}

class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{
    readonly tokens: number;
    readonly resolve: () => void;
  }> = [];
  private processing = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervals * this.refillRate,
      );
      // Advance by whole intervals only, preserving partial-interval progress
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private validateTokenCount(tokens: number): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenCount(tokens);
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Kick the wait queue — reset may unblock waiters
    this.processQueue();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    this.validateTokenCount(tokens);
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens but maxTokens is ${this.maxTokens}`,
      );
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.processQueue();
    });
  }

  private async processQueue(): Promise<void> {
    if (this.processing) return;
    this.processing = true;

    try {
      while (this.waitQueue.length > 0) {
        const head = this.waitQueue[0]!;
        this.refill();

        if (this.tokens >= head.tokens) {
          this.tokens -= head.tokens;
          this.waitQueue.shift();
          head.resolve();
          continue;
        }

        // Calculate exact wait time for the deficit
        const deficit = head.tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const timeSinceLastRefill = Date.now() - this.lastRefillTime;
        const timeUntilNextInterval =
          this.refillIntervalMs - timeSinceLastRefill;
        const waitMs =
          timeUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;

        await new Promise<void>((r) =>
          setTimeout(r, Math.max(1, Math.ceil(waitMs))),
        );
      }
    } finally {
      this.processing = false;
    }
  }
}

export default RateLimiter;

