interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronSchedule;
  min: number;
  max: number;
}

const FIELDS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, { name, min, max }: FieldConfig): number[] => {
  const values = field.split(",").flatMap((part) => {
    const stepMatch = part.match(/^(.+)\/(\d+)$/);
    const step = stepMatch ? parseInt(stepMatch[2], 10) : null;
    const base = stepMatch ? stepMatch[1] : part;

    if (step !== null && (step < 1 || step > max)) {
      throw new Error(`Invalid step value "${step}" for ${name}`);
    }

    let pool: number[];

    if (base === "*") {
      pool = range(min, max);
    } else if (base.includes("-")) {
      const [startStr, endStr] = base.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end) || start > end) {
        throw new Error(`Invalid range "${base}" for ${name}`);
      }
      if (start < min || end > max) {
        throw new Error(`Range "${base}" out of bounds for ${name} (${min}-${max})`);
      }
      pool = range(start, end);
    } else {
      const value = parseInt(base, 10);
      if (isNaN(value) || value < min || value > max) {
        throw new Error(`Invalid value "${base}" for ${name} (${min}-${max})`);
      }
      pool = [value];
    }

    return step !== null ? pool.filter((v) => (v - pool[0]) % step === 0) : pool;
  });

  const unique = [...new Set(values)].sort((a, b) => a - b);

  if (unique.length === 0) {
    throw new Error(`Field ${name} resolved to no values`);
  }

  return unique;
};

function parseCron(expression: string): CronSchedule {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  return Object.fromEntries(
    FIELDS.map((config, i) => [config.name, parseField(parts[i], config)])
  ) as CronSchedule;
}

export default parseCron;

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: unknown,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    return prefix ? { [prefix]: obj } : {};
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = obj;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item, key, result);
      });
    }
    return result;
  }

  const entries = Object.entries(obj as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      flattenObject(value, newKey, result);
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

export default flattenObject;

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
): FlattenedObject {
  const result: FlattenedObject = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      Object.keys(value).length > 0
    ) {
      Object.assign(result, flattenObject(value as Record<string, unknown>, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

export default flattenObject;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: readonly FieldBounds[] = [
  { min: 0, max: 59 },
  { min: 0, max: 23 },
  { min: 1, max: 31 },
  { min: 1, max: 12 },
  { min: 0, max: 6 },
] as const;

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseField(raw: string, bounds: FieldBounds, name: string): number[] {
  const { min, max } = bounds;
  const values = new Set<number>();

  if (raw === "") {
    throw new Error(`Empty ${name} field`);
  }

  for (const part of raw.split(",")) {
    if (part === "") {
      throw new Error(`Trailing or double comma in ${name} field`);
    }

    const [rangeExpr, stepRaw, ...excess] = part.split("/");

    if (excess.length > 0) {
      throw new Error(`Invalid ${name} field segment: "${part}"`);
    }

    const step = stepRaw !== undefined ? parseInt(stepRaw, 10) : 1;

    if (stepRaw !== undefined && (isNaN(step) || step <= 0)) {
      throw new Error(
        `Invalid step "${stepRaw}" in ${name} field — must be a positive integer`
      );
    }

    let start: number;
    let end: number;

    if (rangeExpr === "*") {
      start = min;
      end = max;
    } else if (rangeExpr.includes("-")) {
      const dashParts = rangeExpr.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range "${rangeExpr}" in ${name} field`);
      }
      start = parseInt(dashParts[0], 10);
      end = parseInt(dashParts[1], 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Non-numeric range "${rangeExpr}" in ${name} field`);
      }
      if (start > end) {
        throw new Error(
          `Range start (${start}) exceeds end (${end}) in ${name} field`
        );
      }
      if (start < min || end > max) {
        throw new Error(
          `Range ${start}-${end} outside valid bounds [${min}-${max}] for ${name}`
        );
      }
    } else {
      const val = parseInt(rangeExpr, 10);
      if (isNaN(val) || String(val) !== rangeExpr) {
        throw new Error(`Invalid value "${rangeExpr}" in ${name} field`);
      }
      if (val < min || val > max) {
        throw new Error(
          `Value ${val} outside valid bounds [${min}-${max}] for ${name}`
        );
      }
      if (stepRaw === undefined) {
        values.add(val);
        continue;
      }
      start = val;
      end = max;
    }

    for (let i = start; i <= end; i += step) {
      values.add(i);
    }
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronSchedule {
  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression cannot be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const parsed = fields.map((field, i) =>
    parseField(field, FIELD_BOUNDS[i], FIELD_NAMES[i])
  );

  return {
    minute: parsed[0],
    hour: parsed[1],
    dayOfMonth: parsed[2],
    month: parsed[3],
    dayOfWeek: parsed[4],
  };
}

export default parseCron;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldDef {
  name: keyof CronSchedule;
  min: number;
  max: number;
}

const FIELDS: readonly FieldDef[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function strictInt(s: string): number {
  const t = s.trim();
  if (t === "" || !/^\d+$/.test(t)) return NaN;
  return parseInt(t, 10);
}

function parseField(expr: string, min: number, max: number, name: string): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    const token = part.trim();
    if (token === "") throw new Error(`Empty term in ${name}`);

    const slashIdx = token.indexOf("/");
    let base: string;
    let step: number | null = null;

    if (slashIdx !== -1) {
      base = token.substring(0, slashIdx);
      const stepStr = token.substring(slashIdx + 1);
      step = strictInt(stepStr);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step "${stepStr}" in ${name}`);
      }
    } else {
      base = token;
    }

    if (base === "*") {
      for (let i = min; i <= max; i += step ?? 1) values.add(i);
    } else if (base.includes("-")) {
      const rangeParts = base.split("-");
      if (rangeParts.length !== 2) throw new Error(`Invalid range "${base}" in ${name}`);
      const start = strictInt(rangeParts[0]);
      const end = strictInt(rangeParts[1]);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${base}" in ${name}`);
      if (start > end) throw new Error(`Range start ${start} exceeds end ${end} in ${name}`);
      if (start < min || end > max) {
        throw new Error(`Range ${start}-${end} out of bounds for ${name} (${min}-${max})`);
      }
      for (let i = start; i <= end; i += step ?? 1) values.add(i);
    } else {
      const val = strictInt(base);
      if (isNaN(val)) throw new Error(`Invalid value "${base}" in ${name}`);
      if (val < min || val > max) {
        throw new Error(`Value ${val} out of bounds for ${name} (${min}-${max})`);
      }
      if (step !== null) {
        for (let i = val; i <= max; i += step) values.add(i);
      } else {
        values.add(val);
      }
    }
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const tokens = expression.trim().split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(`Expected 5 fields, got ${tokens.length}: "${expression}"`);
  }

  const result = {} as CronSchedule;
  for (let i = 0; i < FIELDS.length; i++) {
    const { name, min, max } = FIELDS[i];
    result[name] = parseField(tokens[i], min, max, name);
  }
  return result;
}

export default parseCron;

