export interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronSchedule;

interface FieldDef {
  name: FieldName;
  min: number;
  max: number;
}

const FIELDS: readonly FieldDef[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function toInt(str: string, context: string): number {
  if (!/^\d+$/.test(str)) {
    throw new Error(`Invalid integer "${str}" in ${context}`);
  }
  return Number(str);
}

function expandField(token: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const segment of token.split(",")) {
    if (segment === "") {
      throw new Error(`Trailing or empty segment in "${token}"`);
    }

    let base: string;
    let step: number | undefined;

    const slashIdx = segment.indexOf("/");
    if (slashIdx !== -1) {
      base = segment.slice(0, slashIdx);
      step = toInt(segment.slice(slashIdx + 1), `step of "${segment}"`);
      if (step === 0) {
        throw new Error(`Step value must be > 0 in "${segment}"`);
      }
    } else {
      base = segment;
    }

    let lo: number;
    let hi: number;

    if (base === "*") {
      lo = min;
      hi = max;
    } else if (base.includes("-")) {
      const dashIdx = base.indexOf("-");
      lo = toInt(base.slice(0, dashIdx), `range start of "${segment}"`);
      hi = toInt(base.slice(dashIdx + 1), `range end of "${segment}"`);
      if (lo > hi) {
        throw new Error(`Range start ${lo} > end ${hi} in "${segment}"`);
      }
    } else {
      const num = toInt(base, `value "${segment}"`);
      lo = num;
      hi = step !== undefined ? max : num;
    }

    if (lo < min || hi > max) {
      throw new Error(
        `Value out of bounds [${min}\u2013${max}] in "${segment}"`
      );
    }

    for (let v = lo; v <= hi; v += (step ?? 1)) {
      values.add(v);
    }
  }

  if (values.size === 0) {
    throw new Error(`No values produced for "${token}"`);
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronSchedule {
  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${tokens.length}`
    );
  }

  const schedule = {} as CronSchedule;
  for (let i = 0; i < FIELDS.length; i++) {
    const { name, min, max } = FIELDS[i];
    try {
      schedule[name] = expandField(tokens[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field: ${err instanceof Error ? err.message : String(err)}`
      );
    }
  }

  return schedule;
}

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIG: [keyof CronSchedule, number, number][] = [
  ["minute", 0, 59],
  ["hour", 0, 23],
  ["dayOfMonth", 1, 31],
  ["month", 1, 12],
  ["dayOfWeek", 0, 6],
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const all = range(min, max);

  return field.split(",").flatMap((part) => {
    const stepMatch = part.match(/^(.+)\/(\d+)$/);
    const step = stepMatch ? parseInt(stepMatch[2]) : null;
    const base = stepMatch ? stepMatch[1] : part;

    let values: number[];
    if (base === "*") {
      values = all;
    } else if (base.includes("-")) {
      const [s, e] = base.split("-").map(Number);
      if (s < min || e > max || s > e) throw new Error(`Invalid range: ${base}`);
      values = range(s, e);
    } else {
      const n = parseInt(base);
      if (isNaN(n) || n < min || n > max) throw new Error(`Invalid value: ${base}`);
      values = [n];
    }

    return step ? values.filter((_, i) => i % step === 0) : values;
  });
};

export default function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  return Object.fromEntries(
    FIELD_CONFIG.map(([key, min, max], i) => [key, parseField(fields[i], min, max)])
  ) as CronSchedule;
}

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: FlattenedObject = {},
): FlattenedObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const path = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.getPrototypeOf(value) === Object.prototype &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, path, result);
    } else {
      result[path] = value;
    }
  }

  return result;
}

