export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private lastRefillTime: number;
  private readonly queue: Array<{ tokens: number; resolve: () => void }> = [];
  private drainScheduled = false;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0)
      throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd =
      (elapsed / this.refillIntervalMs) * this.refillRate;
    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.scheduleDrain();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) {
      throw new Error(
        `requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`
      );
    }

    // Fast path: tokens available and no one queued ahead of us
    this.refill();
    if (this.queue.length === 0 && this.tokens >= tokens) {
      this.tokens -= tokens;
      return;
    }

    return new Promise<void>((resolve) => {
      this.queue.push({ tokens, resolve });
      this.scheduleDrain();
    });
  }

  private scheduleDrain(): void {
    if (this.drainScheduled || this.queue.length === 0) return;
    this.drainScheduled = true;
    this.drainQueue();
  }

  private drainQueue(): void {
    this.drainScheduled = false;

    while (this.queue.length > 0) {
      this.refill();
      const head = this.queue[0];

      if (this.tokens >= head.tokens) {
        this.tokens -= head.tokens;
        this.queue.shift();
        head.resolve();
        continue;
      }

      // Not enough tokens — schedule wake-up for the deficit
      const deficit = head.tokens - this.tokens;
      const waitMs = Math.ceil(
        (deficit / this.refillRate) * this.refillIntervalMs
      );

      this.drainScheduled = true;
      setTimeout(() => this.drainQueue(), Math.max(1, waitMs));
      return;
    }
  }
}

