const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const all = range(min, max);

  if (field === "*") return all;

  if (field.includes(","))
    return field.flatMap((p) => parseField(p, min, max)).sort((a, b) => a - b);

  if (field.includes("/")) {
    const [base, stepStr] = field.split("/");
    const step = Number(stepStr);
    if (step <= 0 || !Number.isInteger(step)) throw new Error(`Invalid step: ${stepStr}`);
    const values = base === "*" ? all : parseField(base, min, max);
    const start = values[0];
    return values.filter((v) => (v - start) % step === 0);
  }

  if (field.includes("-")) {
    const [s, e] = field.split("-").map(Number);
    if (s < min || e > max || s > e) throw new Error(`Invalid range: ${field}`);
    return range(s, e);
  }

  const n = Number(field);
  if (!Number.isInteger(n) || n < min || n > max) throw new Error(`Invalid value: ${field}`);
  return [n];
};

