  ) as CronSchedule;
}

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const sequence = (start: number, end: number, step = 1): number[] =>
  Array.from({ length: Math.floor((end - start) / step) + 1 }, (_, i) => start + i * step);

const assertInRange = (value: number, min: number, max: number, name: string): void => {
  if (Number.isNaN(value) || value < min || value > max) {
    throw new RangeError(`${name}: ${value} is outside [${min}, ${max}]`);
  }
};

const parseField = (field: string, { name, min, max }: FieldConfig): number[] => {
  if (field.includes(",")) {
    const merged = field
      .split(",")
      .flatMap((part) => parseField(part, { name, min, max }));
    return [...new Set(merged)].sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangeStr, stepStr] = field.split("/", 2);
    const step = Number(stepStr);
    if (Number.isNaN(step) || step <= 0 || !Number.isInteger(step)) {
      throw new RangeError(`${name}: invalid step "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      [start, end] = [min, max];
    } else if (rangeStr.includes("-")) {
      [start, end] = rangeStr.split("-", 2).map(Number);
      assertInRange(start, min, max, name);
      assertInRange(end, min, max, name);
      if (start > end) throw new RangeError(`${name}: invalid range ${start}-${end}`);
    } else {
      start = Number(rangeStr);
      assertInRange(start, min, max, name);
      end = max;
    }

    return sequence(start, end, step);
  }

  if (field === "*") {
    return sequence(min, max);
  }

  if (field.includes("-")) {
    const [start, end] = field.split("-", 2).map(Number);
    assertInRange(start, min, max, name);
    assertInRange(end, min, max, name);
    if (start > end) throw new RangeError(`${name}: invalid range ${start}-${end}`);
    return sequence(start, end);
  }

  const value = Number(field);
  if (!Number.isInteger(value)) {
    throw new TypeError(`${name}: invalid value "${field}"`);
  }
  assertInRange(value, min, max, name);
  return [value];
};

const parseCron = (expression: string): CronSchedule => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields but got ${fields.length}: "${expression}"`);
  }

  const parsed = fields.map((field, i) => parseField(field, FIELD_CONFIGS[i]));
  const [minute, hour, dayOfMonth, month, dayOfWeek] = parsed;

  return { minute, hour, dayOfMonth, month, dayOfWeek };
};

export default parseCron;

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
): FlattenedObject {
  const result: FlattenedObject = {};
  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      Object.assign(result, flattenObject(value as Record<string, unknown>, newKey));
    } else {
      result[newKey] = value;
    }
  }
  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIG: { name: keyof CronFields; min: number; max: number }[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

function parseField(field: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of field.split(",")) {
    const stepMatch = part.match(/^(.+)\/(\d+)$/);
    const step = stepMatch ? Number(stepMatch[2]) : 1;
    const base = stepMatch ? stepMatch[1] : part;

    let start: number, end: number;

    if (base === "*") {
      [start, end] = [min, max];
    } else if (base.includes("-")) {
      const [a, b] = base.split("-").map(Number);
      [start, end] = [a, b];
    } else {
      const val = Number(base);
      if (step > 1) {
        [start, end] = [val, max];
      } else {
        if (val < min || val > max) throw new Error(`Value ${val} out of range [${min}-${max}]`);
        results.add(val);
        continue;
      }
    }

    if (start < min || end > max || start > end) throw new Error(`Range ${start}-${end} invalid for [${min}-${max}]`);

    for (let i = start; i <= end; i += step) results.add(i);
  }

  return [...results].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  return Object.fromEntries(
    FIELD_CONFIG.map((cfg, i) => [cfg.name, parseField(parts[i], cfg.min, cfg.max)])
  ) as CronFields;
}

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: unknown,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    return prefix ? { [prefix]: obj } : {};
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = obj;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item, key, result);
      });
    }
    return result;
  }

  const entries = Object.entries(obj as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      flattenObject(value, newKey, result);
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

export default flattenObject;

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be positive");
    }
    if (options.refillRate <= 0) {
      throw new RangeError("refillRate must be positive");
    }
    if (options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be positive");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervals * this.refillRate,
      );
      // Advance by exact interval multiples to preserve partial-interval remainder
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`,
      );
    }

    while (!this.tryConsume(tokens)) {
      // tryConsume already called refill(), so this.tokens is current
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const targetTime =
        this.lastRefillTime + intervalsNeeded * this.refillIntervalMs;
      const waitMs = Math.max(targetTime - Date.now(), 1);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

type FlattenedObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is Record<string, unknown> =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const flattenObject = (
  obj: Record<string, unknown>,
  prefix = "",
  seen: WeakSet<object> = new WeakSet(),
): FlattenedObject => {
  if (seen.has(obj)) return {};
  seen.add(obj);

  const result: FlattenedObject = {};

  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      Object.assign(result, flattenObject(value, path, seen));
    } else {
      result[path] = value;
    }
  }

  return result;
};

export default flattenObject;

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervals * this.refillRate
      );
      // Advance by whole intervals only, preserving fractional progress
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) return;
    if (!Number.isFinite(tokens) || tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
      );
    }

    while (!this.tryConsume(tokens)) {
      // tryConsume just called refill(), so this.tokens is current
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = Math.max(intervalsNeeded * this.refillIntervalMs, 1);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronSchedule;

const FIELD_RANGES: Record<FieldName, [min: number, max: number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const parseField = (
  field: string,
  [min, max]: [number, number],
  name: string
): number[] => {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    const [rangeOrWildcard, stepStr] = part.split("/", 2);
    const step = stepStr !== undefined ? parseInt(stepStr, 10) : 1;

    if (Number.isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step "${stepStr}" in ${name} field`);
    }

    let start: number;
    let end: number;

    if (rangeOrWildcard === "*") {
      start = min;
      end = max;
    } else if (rangeOrWildcard.includes("-")) {
      const parts = rangeOrWildcard.split("-", 2);
      start = parseInt(parts[0], 10);
      end = parseInt(parts[1], 10);
      if (Number.isNaN(start) || Number.isNaN(end)) {
        throw new SyntaxError(
          `Invalid range "${rangeOrWildcard}" in ${name} field`
        );
      }
    } else {
      const num = parseInt(rangeOrWildcard, 10);
      if (Number.isNaN(num)) {
        throw new SyntaxError(
          `Invalid value "${rangeOrWildcard}" in ${name} field`
        );
      }
      start = num;
      end = stepStr !== undefined ? max : num;
    }

    if (start < min || start > max || end < min || end > max) {
      throw new RangeError(
        `Value out of range [${min}-${max}] in ${name} field`
      );
    }
    if (start > end) {
      throw new RangeError(
        `Start ${start} exceeds end ${end} in ${name} field`
      );
    }

    for (let i = start; i <= end; i += step) {
      values.add(i);
    }
  }

  if (values.size === 0) {
    throw new SyntaxError(`Empty result for ${name} field`);
  }

  return [...values].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronSchedule => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length}: "${expression}"`
    );
  }

  return Object.fromEntries(
    FIELD_ORDER.map((name, i) => [
      name,
      parseField(fields[i], FIELD_RANGES[name], name),
    ])
  ) as CronSchedule;
};

export default parseCron;

type FlattenedResult = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(input: Record<string, unknown>): FlattenedResult {
  const result: FlattenedResult = {};
  const ancestors = new WeakSet();

  function recurse(current: Record<string, unknown>, prefix: string): void {
    ancestors.add(current);

    for (const key of Object.keys(current)) {
      const path = prefix ? `${prefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        if (ancestors.has(value)) continue;
        if (Object.keys(value).length === 0) {
          result[path] = value;
        } else {
          recurse(value, path);
        }
      } else {
        result[path] = value;
      }
    }

    ancestors.delete(current);
  }

  recurse(input, "");
  return result;
}

export default flattenObject;

class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new Error("maxTokens must be positive");
    if (options.refillRate <= 0) throw new Error("refillRate must be positive");
    if (options.refillIntervalMs <= 0)
      throw new Error("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new Error("tokens must be positive");
    if (tokens > this.maxTokens)
      throw new Error("requested tokens exceed maxTokens");

    while (true) {
      this.refill();

      if (this.tokens >= tokens) {
        this.tokens -= tokens;
        return;
      }

      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const now = Date.now();
      const nextRefillAt =
        this.lastRefillTime + this.refillIntervalMs - now;
      const waitMs =
        Math.max(0, nextRefillAt) +
        Math.max(0, intervalsNeeded - 1) * this.refillIntervalMs;

      await new Promise((resolve) =>
        setTimeout(resolve, Math.max(1, waitMs))
      );
    }
  }
}

export default RateLimiter;

type FlattenedObject = Record<string, unknown>;

function flattenObject(
  obj: unknown,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    return prefix ? { [prefix]: obj } : {};
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = obj;
    } else {
      obj.forEach((item, i) => {
        flattenObject(item, prefix ? `${prefix}.${i}` : `${i}`, result);
      });
    }
    return result;
  }

  const entries = Object.entries(obj as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object" && !Array.isArray(value) && Object.keys(value as object).length > 0) {
      flattenObject(value, newKey, result);
    } else if (Array.isArray(value) && value.length > 0) {
      flattenObject(value, newKey, result);
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

export default flattenObject;
